var cols = Math.Max(1, GetInt(parameters, "columns", 4));
var rows = Math.Max(1, GetInt(parameters, "rows", 4));
var bgColor = GetColor(parameters, "bgColor", System.Windows.Media.Color.FromRgb(64, 64, 64));
var size = context.TileSize;
var result = new PixelBuffer(size, size);
var bgR=bgColor.R/255f; var bgG=bgColor.G/255f; var bgB=bgColor.B/255f;
var cellW = size / (float)cols;
var cellH = size / (float)rows;
result.ParallelForEachPixel((x, y) =>
{
    var col = (int)(x / cellW);
    var row = (int)(y / cellH);
    var localX = x / cellW - col;
    var localY = y / cellH - row;
    // Checkerboard tint for alternating cells
    var checker = (col + row) % 2 == 0;
    var cellR = checker ? bgR * 1.2f : bgR * 0.8f;
    var cellG = checker ? bgG * 1.2f : bgG * 0.8f;
    var cellB2 = checker ? bgB * 1.2f : bgB * 0.8f;
    // Grid lines
    var lineW = Math.Max(1f, size * 0.008f);
    var onLineX = x % (size / cols) < lineW || x % (size / cols) > (size / cols) - lineW;
    var onLineY = y % (size / rows) < lineW || y % (size / rows) > (size / rows) - lineW;
    if (onLineX || onLineY)
    {
        result.SetPixel(x, y, 1f, 1f, 1f, 0.6f);
    }
    else
    {
        // Corner markers for center
        var distC = MathF.Sqrt((localX-0.5f)*(localX-0.5f) + (localY-0.5f)*(localY-0.5f));
        var dot = distC < 0.08f ? 0.5f : 0f;
        result.SetPixel(x, y, Math.Clamp(cellR + dot, 0,1), Math.Clamp(cellG + dot, 0,1), Math.Clamp(cellB2 + dot, 0,1), 1f);
    }
});
return result;
}
